#include<bits/stdc++.h>
using namespace std;

map<int, bool> mp;
queue<int> q;
int n, m, ans;
int main() {
	cin >> n >> m;
	for (int i = 1; i <= m; i++) {
		int x;
		cin >> x;
		if (!mp[x]) {
            mp[x]=1;
			if (q.size() == n) {

				mp[q.front()] = 0;
				q.pop();
				q.push(x);

			} else {
				q.push(x);
			}
			ans++;
		}
	}
	cout<<ans;
}
